VALUES
  ('diplomatic-9e854390-moex-00146', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於俄羅斯與烏克蘭「黑海穀物倡議」（BlackSeaGrainInitiative）的敘述最不適當？', '["是俄、烏兩國在土耳其的斡旋下，加上聯合國的背書，四方於2022年7月共同簽署的國際文件", "不僅烏克蘭的穀物，還包括俄羅斯原本經過烏克蘭出海的穀物，均可安全地由黑海的任何港口 出口", "前往載貨的船隻必須在伊斯坦堡接受安檢方能進入黑海的「人道主義走廊」", "俄羅斯曾數次暫停參與該協議，致使聯合國擔心最貧窮國家的糧食供應可能會出現更大的危機"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00147', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於我國與歐洲區域外交關係的敘述最不適當？', '["除了與梵蒂岡有正式外交關係且互派大使外，我國與其他歐洲國家均無正式外交關係", "馬爾他騎士團近年曾於世界衛生大會（WHA）發言支持我國", "我國在歐洲最新的駐米蘭臺北辦事處將於2023下半年開館運作", "我國與歐盟雖無正式外交關係，但有若干非關高度主權意涵的部長級對話會議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00148', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於聯合國永續發展目標（SDGs）的敘述錯誤？', '["由聯合國於2015年宣布，總共有17項", "聯合國會員國同意盡力於2030年之前達成目標", "排序第一位的永續發展目標是「良好健康與福祉」", "三大原則分別是基於人權的作為、一個都不能少、性別平等及女性賦權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00149', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於2023年美國與中國大陸「科技戰」的敘述最不適當？', '["美國可能計畫針對中國大陸的雲端計算技術和網路技術服務加以限制", "美國為了抑制中國大陸高階晶片的自主製造，持續推動友岸外包（friendlyshoring）政策", "中國大陸的反制作為包括展開基礎科技研發體制改革，鼓勵有能力的政府及社會組織加大相關 資金的投入", "美國對於台積電、三星售予中國大陸高階晶片的豁免期，已於2023年7月結束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00150', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於我國在中美洲及加勒比海外交的敘述錯誤？', '["巴拿馬於2017年與我國斷交後，成為該地區首個加入中國大陸「一帶一路」倡議的國家", "2023年7月時，我國在加勒比海地區有聖文森、聖克里斯多福及尼維斯、聖露西亞、海地四個 邦交國", "2023年7月時，我國是中美洲議會（Parlacen）的觀察員、中美洲銀行（CABEI）的區域外會 員國", "2023年夏，多明尼加向中美洲銀行提案要求排除我國參與，改由中國大陸取代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00151', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於「國家保護責任」（responsibilitytoprotect）的敘述錯誤？', '["產生的背景是冷戰結束後，人類的武裝衝突有越來越多是一國的內戰或一國內部的大規模暴行", "該名詞於2001年由聯合國安理會經過激辯後提出，並賦予國家更多責任", "2005年的聯合國高峰會提出了相關的三個支柱，後由聯合國秘書長的報告予以充實", "因為牽涉到如何合法使用武力，所以聯合國並未對介入的判斷條件予以嚴格定義，而是採個案 處理的方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00152', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於氣候變遷的敘述最不適當？', '["2015年的「巴黎協定」（ParisAgreement）具有里程碑的意義", "前述協定要求強化「華沙損失與損害機制」（WarsawInternationalMechanismforLossandDamage）", "美國強力要求前述機制應獲得完全的法律設計與保障，每個國家均因此負擔法律救濟責任", "氣候變遷所帶來的人類自願或非自願移動，使得「氣候難民」的成因更加複雜"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00153', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項關於國際刑事法院（ICC）的敘述錯誤？', '["具體設立及實際運行是以聯合國憲章及國際人權法典為主", "以屬人管轄和屬地管轄為法院行使管轄權的依據", "相關法規規定，在特定情況下，法院可對非締約國實施管轄權，無論非締約國同意與否", "為顧及國家主權，法院只有在非締約國對相關罪行不能或不願行使管轄權時才可以行使管轄權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00154', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一個阿拉伯國家於2020年與以色列簽署了正式的和平協議？', '["阿拉伯聯合大公國", "沙烏地阿拉伯", "埃及", "約旦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00155', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列何者是評估侵犯人權行為並提出建議的主要政府間組織？', '["國際特赦組織（AmnestyInternational）", "聯合國人權事務高級專員辦事處（Office of the United Nations High Commissioner for Human Rights）", "聯合國人權理事會（HumanRightsCommittee）", "歐洲人權法院（EuropeanCourtofHumanRights）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
